import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"紫竹院公园","description":"","frontmatter":{},"headers":[],"relativePath":"parks/zizhuyuan.md","filePath":"parks/zizhuyuan.md","lastUpdated":null}'),n={name:"parks/zizhuyuan.md"};function d(i,t,o,s,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="紫竹院公园" tabindex="-1">紫竹院公园 <a class="header-anchor" href="#紫竹院公园" aria-label="Permalink to &quot;紫竹院公园&quot;">​</a></h1><blockquote><p>&quot;竹影婆娑，人少景美的城市公园。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>紫竹院公园位于北京市海淀区，是一座以竹为景的城市公园。公园占地约47公顷，其中水面约15公顷，是北京著名的竹景名园。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">6:00-21:00（旺季），6:00-20:00（淡季）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">1-2小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">夏季荷花</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁4号线/9号线国家图书馆站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市海淀区中关村南大街35号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="始建" tabindex="-1">始建 <a class="header-anchor" href="#始建" aria-label="Permalink to &quot;始建&quot;">​</a></h3><p>紫竹院公园所在地原是一片洼地，清代在此修建行宫，种植竹子。</p><h3 id="现代公园" tabindex="-1">现代公园 <a class="header-anchor" href="#现代公园" aria-label="Permalink to &quot;现代公园&quot;">​</a></h3><p>1953年，辟为公园，取名&quot;紫竹院&quot;。此后不断扩大规模，增加竹种。</p><h2 id="竹景" tabindex="-1">竹景 <a class="header-anchor" href="#竹景" aria-label="Permalink to &quot;竹景&quot;">​</a></h2><h3 id="竹林" tabindex="-1">竹林 <a class="header-anchor" href="#竹林" aria-label="Permalink to &quot;竹林&quot;">​</a></h3><p>紫竹院公园种植了各种竹子，是北京著名的竹景公园。</p><table tabindex="0"><thead><tr><th style="text-align:left;">竹种</th><th style="text-align:left;">特点</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>紫竹</strong></td><td style="text-align:left;">竹秆紫色，公园名由此而来</td></tr><tr><td style="text-align:left;"><strong>斑竹</strong></td><td style="text-align:left;">竹秆有斑点</td></tr><tr><td style="text-align:left;"><strong>苦竹</strong></td><td style="text-align:left;">竹秆有苦味</td></tr><tr><td style="text-align:left;"><strong>早园竹</strong></td><td style="text-align:left;">生长迅速</td></tr><tr><td style="text-align:left;"><strong>毛竹</strong></td><td style="text-align:left;">竹秆粗壮</td></tr></tbody></table><h3 id="竹文化" tabindex="-1">竹文化 <a class="header-anchor" href="#竹文化" aria-label="Permalink to &quot;竹文化&quot;">​</a></h3><p>紫竹院公园以竹文化为主题，有竹文化展览、竹工艺品展示等。</p><h2 id="主要景点" tabindex="-1">主要景点 <a class="header-anchor" href="#主要景点" aria-label="Permalink to &quot;主要景点&quot;">​</a></h2><h3 id="荷花渡" tabindex="-1">荷花渡 <a class="header-anchor" href="#荷花渡" aria-label="Permalink to &quot;荷花渡&quot;">​</a></h3><p>夏季，荷花渡荷花盛开，是赏荷的好地方。</p><h3 id="问月楼" tabindex="-1">问月楼 <a class="header-anchor" href="#问月楼" aria-label="Permalink to &quot;问月楼&quot;">​</a></h3><p>问月楼是公园的主要建筑，可以登楼远眺。</p><h3 id="澄碧山房" tabindex="-1">澄碧山房 <a class="header-anchor" href="#澄碧山房" aria-label="Permalink to &quot;澄碧山房&quot;">​</a></h3><p>澄碧山房是公园的水上建筑，环境清幽。</p><h3 id="八宜轩" tabindex="-1">八宜轩 <a class="header-anchor" href="#八宜轩" aria-label="Permalink to &quot;八宜轩&quot;">​</a></h3><p>八宜轩是公园的亭子，&quot;八宜&quot;指&quot;春宜花，夏宜风，秋宜月，冬宜雪，昼宜棋，夜宜琴，晴宜书，雨宜酒&quot;。</p><h2 id="游船" tabindex="-1">游船 <a class="header-anchor" href="#游船" aria-label="Permalink to &quot;游船&quot;">​</a></h2><p>公园内有水面，可以划船、脚踏船。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>经典路线（约1-2小时）</strong>：</p><p>南门 → 荷花渡 → 问月楼 → 澄碧山房 → 八宜轩 → 竹林 → 北门</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">4号线/9号线国家图书馆站D口</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">86路、92路、332路等白石桥东站</td></tr><tr><td style="text-align:left;">步行</td><td style="text-align:left;">从动物园步行约15分钟</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>免费入园</strong>：公园免费开放</li><li><strong>人少清静</strong>：游客较少，比较清静</li><li><strong>夏季荷花</strong>：夏季荷花盛开</li><li><strong>竹景优美</strong>：竹影婆娑，非常优美</li><li><strong>划船体验</strong>：可以划船游湖</li><li><strong>结合游览</strong>：可与动物园、国家图书馆一起游览</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">国家图书馆</td><td style="text-align:center;">紧邻</td><td style="text-align:left;">亚洲最大图书馆</td></tr><tr><td style="text-align:left;">北京动物园</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">大熊猫</td></tr><tr><td style="text-align:left;">北京天文馆</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">天文科普</td></tr><tr><td style="text-align:left;">中国古动物馆</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">古动物化石</td></tr></tbody></table><hr><p><strong>📍 地址</strong>：北京市海淀区中关村南大街35号 <strong>📞 电话</strong>：010-68422285</p>',40)])])}const u=e(n,[["render",d]]);export{f as __pageData,u as default};
